"""Convert MXML event logs into XES files.Usage:  python tools/mxml2xes_convertor.py --input "../Data/Business Process Drift/logs/cb/cb2.5k.mxml" --output "../Data/Business Process Drift/logs/cb/cb2.5k.xes""""from __future__ import annotationsimport argparsefrom datetime import datetime, timezonefrom pathlib import Pathfrom typing import Optionalfrom lxml import etreeimport pm4pyfrom pm4py.objects.log.obj import Event, EventLog, Tracedef _strip_ns(tag: str) -> str:    """Remove XML namespace from a tag name."""    return tag.split("}", 1)[-1] if "}" in tag else tagdef _child_text(elem: etree._Element, child_name: str) -> Optional[str]:    """Read first direct child text by local tag name."""    for child in elem:        if _strip_ns(child.tag) == child_name:            text = child.text.strip() if child.text else ""            return text or None    return Nonedef _parse_timestamp(raw: Optional[str]) -> Optional[datetime]:    """Parse MXML timestamp text into timezone-aware datetime."""    if not raw:        return None    text = raw.strip()    if not text:        return None    normalized = text.replace("Z", "+00:00")    try:        dt = datetime.fromisoformat(normalized)    except ValueError:        return None    if dt.tzinfo is None:        dt = dt.replace(tzinfo=timezone.utc)    return dtdef _extract_data_attributes(data_elem: Optional[etree._Element]) -> dict[str, str]:    """Extract <Data><Attribute name=...>value</Attribute></Data> into a mapping."""    attrs: dict[str, str] = {}    if data_elem is None:        return attrs    for child in data_elem:        if _strip_ns(child.tag) != "Attribute":            continue        key = (child.get("name") or "").strip()        if not key:            continue        value = child.text.strip() if child.text else ""        attrs[key] = value    return attrsdef parse_mxml_to_event_log(mxml_path: Path) -> EventLog:    """Parse standard MXML WorkflowLog into pm4py EventLog."""    parser = etree.XMLParser(remove_comments=True, recover=True, huge_tree=True)    tree = etree.parse(str(mxml_path), parser=parser)    root = tree.getroot()    log = EventLog()    trace_counter = 0    for process_instance in root.iter():        if _strip_ns(process_instance.tag) != "ProcessInstance":            continue        case_id = (process_instance.get("id") or "").strip()        if not case_id:            case_id = f"case_{trace_counter}"        trace = Trace()        trace.attributes["concept:name"] = case_id        trace_data_elem = next((c for c in process_instance if _strip_ns(c.tag) == "Data"), None)        for key, value in _extract_data_attributes(trace_data_elem).items():            trace.attributes[key] = value        for audit_entry in process_instance:            if _strip_ns(audit_entry.tag) != "AuditTrailEntry":                continue            event = Event()            activity = _child_text(audit_entry, "WorkflowModelElement") or "UNKNOWN_ACTIVITY"            event_type = (_child_text(audit_entry, "EventType") or "complete").lower()            timestamp = _parse_timestamp(_child_text(audit_entry, "Timestamp"))            originator = _child_text(audit_entry, "Originator") or "UNKNOWN"            event["concept:name"] = activity            event["lifecycle:transition"] = event_type            event["org:resource"] = originator            if timestamp is not None:                event["time:timestamp"] = timestamp            event_data_elem = next((c for c in audit_entry if _strip_ns(c.tag) == "Data"), None)            for key, value in _extract_data_attributes(event_data_elem).items():                event[key] = value            trace.append(event)        # Keep non-empty traces only.        if len(trace) > 0:            log.append(trace)            trace_counter += 1    return logdef convert_mxml_to_xes(input_path: Path, output_path: Path) -> None:    """Convert one MXML file into one XES file."""    if not input_path.exists():        raise FileNotFoundError(f"MXML file not found: {input_path}")    if input_path.suffix.lower() != ".mxml":        raise ValueError(f"Input file must have .mxml extension, got: {input_path}")    output_path.parent.mkdir(parents=True, exist_ok=True)    print(f"Reading MXML: {input_path}")    log = parse_mxml_to_event_log(input_path)    print(f"Parsed traces: {len(log)}")    print(f"Writing XES: {output_path}")    pm4py.write_xes(log, str(output_path))    print("Done.")def _build_arg_parser() -> argparse.ArgumentParser:    parser = argparse.ArgumentParser(description="Convert MXML event logs to XES.")    parser.add_argument("--input", "-i", required=True, help="Path to input .mxml file.")    parser.add_argument("--output", "-o", required=True, help="Path to output .xes file.")    return parserdef main() -> None:    args = _build_arg_parser().parse_args()    convert_mxml_to_xes(Path(args.input).expanduser().resolve(), Path(args.output).expanduser().resolve())if __name__ == "__main__":    main()